var TEMPLATE_TAGS=[{id:1,name:"RId",description:"收件人的唯一标识。"},{id:2,name:"FullName",description:"收件人的姓名。"},{id:3,name:"Position",description:"收件人的职位。"},{id:4,name:"From",description:"邮件的发件地址。"},{id:5,name:"TrackingURL",description:"用于追踪邮件是否被打开的URL。"},{id:6,name:"Tracker",description:"添加隐藏追踪图片的HTML标签（推荐替代TrackingURL）。"},{id:7,name:"URL",description:"您的Gophish-EVO监听器URL。"},{id:8,name:"BaseURL",description:"去除路径和rid参数的基础URL，适用于静态文件链接。"},{id:9,name:"QRCode",description:"链接到钓鱼URL的二维码图片。"}],textTestCallback=function(t){return t.collapsed?CKEDITOR.plugins.textMatch.match(t,matchCallback):null},matchCallback=function(t,e){var i=t.slice(0,e).match(/\{{2}\.?([A-z]|\})*$/);return i?{start:i.index,end:e}:null},dataCallback=function(t,e){e(TEMPLATE_TAGS.filter(function(e){return 0==("{{."+e.name.toLowerCase()+"}}").indexOf(t.query.toLowerCase())}))},setupAutocomplete=function(t){t.on("instanceReady",function(t){new CKEDITOR.plugins.autocomplete(t.editor,{textTestCallback:textTestCallback,dataCallback:dataCallback,itemTemplate:'<li data-id="{id}"><div><strong class="item-title">{name}</strong></div><div><i>{description}</i></div></li>',outputTemplate:"[[.{name}]]"}).getHtmlToInsert=function(t){var e=this.outputTemplate.output(t);return e=e.replace("[[","{{").replace("]]","}}")}})};